-- Replicates the age-standardised rate chart (Men / Women / Persons lines)
CREATE OR REPLACE VIEW v_mortality_asr_by_sex AS
SELECT year, asr_men, asr_women, asr_persons
FROM dementia_mortality
ORDER BY year;

-- Death counts by sex
CREATE OR REPLACE VIEW v_mortality_deaths_by_sex AS
SELECT year, deaths_men, deaths_women, deaths_persons
FROM dementia_mortality
ORDER BY year;

-- Crude rates by sex
CREATE OR REPLACE VIEW v_mortality_crude_by_sex AS
SELECT year, crude_men, crude_women, crude_persons
FROM dementia_mortality
ORDER BY year;
-- AIHW Australian Burden of Disease Study 2024 National Disease Burden Data
-- Source: Table S1. Number (YLL, YLD, DALY) and crude rate by sex, year, and 5-year age groups
-- Disease group: Neurological conditions
-- Diseases: Dementia, Epilepsy, Guillain-Barre Syndrome, Migraine, Motor neurone disease,
--           Multiple sclerosis, Other neurological conditions, Parkinson disease
-- Years: 2003, 2011, 2015, 2018, 2024
-- Sex: Females, Males, Persons
-- Age groups: 0, 1-4, 5-9, ..., 95-99, 100+, Total

DROP TABLE IF EXISTS neurological_burden;

CREATE TABLE neurological_burden (
    id                   SERIAL         PRIMARY KEY,
    year                 SMALLINT       NOT NULL,
    disease_group        VARCHAR(50)    NOT NULL,
    disease              VARCHAR(100)   NOT NULL,
    sex                  VARCHAR(10)    NOT NULL,   -- 'Females', 'Males', 'Persons'
    age_group            VARCHAR(10)    NOT NULL,   -- '0', '1-4', ..., '100+', 'Total'
    yll                  INTEGER,                   -- Years of life lost
    crude_yll_rate       NUMERIC(10,3), -- Per 1,000 population
    yld                  INTEGER,                   -- Years lived with disability
    crude_yld_rate       NUMERIC(10,3), -- Per 1,000 population
    daly                 INTEGER,                   -- Disability-adjusted life years
    crude_daly_rate      NUMERIC(10,3), -- Per 1,000 population
    standard_population  BIGINT,        -- Only populated for Total age rows

    CONSTRAINT chk_sex CHECK (sex IN ('Females', 'Males', 'Persons'))
);

