-- Useful indexes for filtering
CREATE INDEX idx_nb_year     ON neurological_burden (year);
CREATE INDEX idx_nb_disease  ON neurological_burden (disease);
CREATE INDEX idx_nb_sex      ON neurological_burden (sex);
CREATE INDEX idx_nb_age      ON neurological_burden (age_group);

-- Replicates the chart: Dementia DALY + crude rate by age group for Persons in 2024
CREATE OR REPLACE VIEW v_dementia_daly_by_age_2024 AS
SELECT age_group, daly, crude_daly_rate
FROM neurological_burden
WHERE disease = 'Dementia'
  AND sex = 'Persons'
  AND year = 2024
  AND age_group != 'Total'
ORDER BY
  CASE age_group
    WHEN '0'     THEN 0
    WHEN '1–4'   THEN 1
    WHEN '5–9'   THEN 2
    WHEN '10–14' THEN 3
    WHEN '15–19' THEN 4
    WHEN '20–24' THEN 5
    WHEN '25–29' THEN 6
    WHEN '30–34' THEN 7
    WHEN '35–39' THEN 8
    WHEN '40–44' THEN 9
    WHEN '45–49' THEN 10
    WHEN '50–54' THEN 11
    WHEN '55–59' THEN 12
    WHEN '60–64' THEN 13
    WHEN '65–69' THEN 14
    WHEN '70–74' THEN 15
    WHEN '75–79' THEN 16
    WHEN '80–84' THEN 17
    WHEN '85–89' THEN 18
    WHEN '90–94' THEN 19
    WHEN '95–99' THEN 20
    WHEN '100+'  THEN 21
  END;

-- Total DALY summary across all neurological diseases for Persons, 2024
CREATE OR REPLACE VIEW v_all_neurological_totals_2024 AS
SELECT disease, yll, yld, daly, crude_daly_rate
FROM neurological_burden
WHERE sex = 'Persons'
  AND year = 2024
  AND age_group = 'Total'
ORDER BY daly DESC NULLS LAST;

-- Dementia DALY trend over all years (Persons, Total age)
CREATE OR REPLACE VIEW v_dementia_daly_trend AS
SELECT year, sex, daly, crude_daly_rate, standard_population
FROM neurological_burden
WHERE disease = 'Dementia'
  AND age_group = 'Total'
ORDER BY year, sex;
-- AIHW Dementia Burden of Disease Data (2024)
-- Source: AIHW Table S4.1 Leading 10 causes of disease burden (DALY) in Australia in 2024
-- Breakdown by sex (Men / Women / Persons) and age group
-- Year is fixed at 2024 (as per the source table)

DROP TABLE IF EXISTS dementia_burden_of_disease;

CREATE TABLE dementia_burden_of_disease (
    id          SERIAL        PRIMARY KEY,
    year        SMALLINT      NOT NULL DEFAULT 2024,
    sex         VARCHAR(10)   NOT NULL,  -- 'Men', 'Women', 'Persons'
    age_group   VARCHAR(10)   NOT NULL,  -- 'Under 30', '30-64', '65-69', ..., '100+', 'Total'
    rank        SMALLINT      NOT NULL,  -- 1 (highest burden) to 10
    disease     TEXT          NOT NULL,
    daly        INTEGER       NOT NULL,

    CONSTRAINT chk_sex CHECK (sex IN ('Men', 'Women', 'Persons')),
    CONSTRAINT chk_rank CHECK (rank BETWEEN 1 AND 10)
);

